
# 1. Genera una clave privada PKI y una CSR, y asígnales los nombres «learner.key» y «learner.csr», respectivamente.

openssl genrsa -out learner.key 2048
openssl req -new -key learner.key -out learner.csr -subj "/CN=learner" 

# 2. Crea una solicitud de firma de certificado (CSR) para «learner» y establece la fecha de caducidad en 1 semana.

# generar el certificado en base64 para pasarlo al yaml de la firma de certificado
# 3. Asegúrate de utilizar el valor codificado de «csr» en el campo de solicitud. listo
cat learner.csr | base64 | tr -d "\n"


# pasamos el certificado al yaml de la firma de certificado 
k apply -f csr2.yaml


# 4. Aprueba la CSR.

# verificar si el certificado si fue creado correctamnete 
k get csr 

# aprobar el csr 
k certificate approve learner 

# 5. Recupera el certificado de la CSR.
k get csr learner - o yaml 

# 6. Exporta el certificado emitido desde la solicitud de firma de certificado a un archivo YAML.
k get csr learner -o yaml > issuecert2.yaml

# 7. Redirige el valor del certificado al archivo «learner.crt» tras descodificarlo.
echo "" | base64 -d
